import type { TimetableAssignment } from '@/lib/types'

interface Props {
  assignments: TimetableAssignment[]
  days?: string[]
}

const DEFAULT_DAYS = ['lundi', 'mardi', 'mercredi', 'jeudi', 'vendredi']

export default function TimetableGrid({ assignments, days = DEFAULT_DAYS }: Props) {
  if (!assignments.length) {
    return (
      <div className="flex items-center justify-center h-48 text-gray-400 text-sm">
        Aucun résultat disponible
      </div>
    )
  }

  const byDay: Record<string, TimetableAssignment[]> = {}
  for (const day of days) byDay[day] = []
  for (const a of assignments) {
    if (byDay[a.day]) byDay[a.day].push(a)
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full border-collapse text-sm">
        <thead>
          <tr>
            {days.map(d => (
              <th
                key={d}
                className="px-3 py-2 text-left font-medium text-gray-600 dark:text-gray-400 border-b border-gray-200 dark:border-gray-700 capitalize"
              >
                {d}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          <tr>
            {days.map(day => (
              <td key={day} className="px-2 py-2 align-top border-r last:border-r-0 border-gray-100 dark:border-gray-800">
                <div className="flex flex-col gap-1.5">
                  {byDay[day].map((a, i) => (
                    <div
                      key={i}
                      className="rounded-lg p-2 text-xs"
                      style={{ backgroundColor: a.color + '22', borderLeft: `3px solid ${a.color}` }}
                    >
                      <p className="font-medium text-gray-900 dark:text-gray-100">{a.subject}</p>
                      <p className="text-gray-500 dark:text-gray-400">{a.teacher}</p>
                      <p className="text-gray-400 dark:text-gray-500">{a.start_time}–{a.end_time}</p>
                      <p className="text-gray-400 dark:text-gray-500">{a.room} · {a.school_class}</p>
                    </div>
                  ))}
                </div>
              </td>
            ))}
          </tr>
        </tbody>
      </table>
    </div>
  )
}
